// "---- 🚀 Hybrid Authentication Approach-------"

import jwt from "jsonwebtoken";
import { refreshAccessToken } from "../Services/auth.service.js";
import { ACCESS_TOKEN_EXPIRY, REFRESH_TOKEN_EXPIRY } from "../Config/constants.js";

export const requireAuth = async (req, res, next) => {
  const accessToken = req.cookies.access_token;
  const refreshToken = req.cookies.refresh_token;

  // console.log("\nAcccess Token and the Refresh Token: ", accessToken, refreshToken);
  req.user = null;

  // "If both are not available that means user clicks on logout or lifetime of both token get expired"
  if (!accessToken && !refreshToken) {
    return res.status(401).json({ error: "Unauthorized: Please log in." });
  }

  // "Before accessing to any secure api path check the access tocken is expired or not"
  if (accessToken) {
    try {
      const decoded = jwt.verify(accessToken, process.env.JWT_KEY);
      req.user = decoded;
      return next();
    } catch (err) {
      if (err.name !== "TokenExpiredError") {
        return res.status(401).json({ error: "Invalid Access Token" });
      }
      // If it's TokenExpiredError, we DO NOT throw. We simply fall through to the refreshToken block!
    }
  }

  // "If the access token get expired then get a new access token created using refresh token"
  if (refreshToken) {
    try {
      const { newAccessToken, newRefreshToken, user } =
        await refreshAccessToken(refreshToken);

      const isProduction = process.env.NODE_ENV === "production";

      // {iv. Send the access token to frontend}
      res.cookie("access_token", newAccessToken, {
        httpOnly: true,
        secure: isProduction,
        sameSite: isProduction ? "none" : "lax",
        maxAge: ACCESS_TOKEN_EXPIRY,
      });

      // {v. Send the refresh token to frontend}
      res.cookie("refresh_token", newRefreshToken, {
        httpOnly: true,
        secure: isProduction,
        sameSite: isProduction ? "none" : "lax",
        maxAge: REFRESH_TOKEN_EXPIRY,
      });

      req.user = user; // They forgot this! If we refresh, we must populate req.user so the route gets handled!
      return next();
    } catch (error) {
      console.log("Refresh token error: ", error.message);
      res.clearCookie("access_token");
      res.clearCookie("refresh_token");
      return res.status(401).json({ error: "Session Expired. Please login again." });
    }
  }

  return res.status(401).json({ error: "Unauthorized Check Failed" });
};
